89	// NewLocalLandCoordinator returns a process-local LandCoordinator for use
90	// by CLI commands such as `ddx work` / `ddx agent execute-loop`. It has the same
91	// single-writer semantics as the server-hosted coordinator but its lifetime
92	// is tied to the CLI invocation. Stop() should be called on function exit.
93	func NewLocalLandCoordinator(projectRoot string, gitOps agent.LandingGitOps) *LandCoordinator {
94		return newLandCoordinator(projectRoot, gitOps)
95	}
96	
97	func newLandCoordinator(projectRoot string, gitOps agent.LandingGitOps) *LandCoordinator {
98		if gitOps == nil {
99			gitOps = agent.RealLandingGitOps{}
100		}
101		c := &LandCoordinator{
102			projectRoot: projectRoot,
103			gitOps:      gitOps,
104			// Buffered so a single-worker happy path does not block on a
105			// channel handoff. Additional submissions queue up naturally.
106			queue: make(chan *LandSubmission, 32),
107			done:  make(chan struct{}),
108		}
109		go c.run()
110		return c
111	}
112	
113	// Submit sends req to the coordinator and blocks until the LandResult is
114	// available. Safe to call concurrently from any number of goroutines — the
115	// coordinator processes submissions in FIFO order.
116	func (c *LandCoordinator) Submit(req agent.LandRequest) (*agent.LandResult, error) {
117		sub := &LandSubmission{
118			Request: req,
119			replyCh: make(chan landReply, 1),
120		}
121		select {
122		case c.queue <- sub:
123		case <-c.done:
124			return nil, fmt.Errorf("land coordinator for %s has stopped", c.projectRoot)
125		}
126		reply := <-sub.replyCh
127		return reply.result, reply.err
128	}
129	
130	// Stop closes the submission queue and signals the coordinator goroutine to
131	// exit after draining any in-flight submissions. Intended for test cleanup
132	// and process shutdown; not currently called from the server HTTP path.
133	func (c *LandCoordinator) Stop() {
134		select {
135		case <-c.done:
136			return
137		default:
138		}
139		close(c.done)
140		close(c.queue)
141	}
142	
143	// run is the coordinator goroutine. It drains queue in FIFO order, calling
144	// agent.Land() for each submission. One submission at a time — this is the
145	// single-writer guarantee for target-ref writes on projectRoot.
146	func (c *LandCoordinator) run() {
147		for sub := range c.queue {
148			start := time.Now()
149			result, err := agent.Land(c.projectRoot, sub.Request, c.gitOps)
150			elapsed := time.Since(start)
151			c.recordMetrics(sub.Request, result, err, elapsed)
152			sub.replyCh <- landReply{result: result, err: err}
153		}
154	}
