18	
19		loopCmd, _, err := root.Find([]string{"agent", "execute-loop"})
20		if err != nil {
21			t.Fatalf("ddx agent execute-loop not found: %v", err)
22		}
23	
24		// Collect local flag names from each command
25		workFlags := map[string]bool{}
26		workCmd.Flags().VisitAll(func(f *pflag.Flag) {
27			workFlags[f.Name] = true
28		})
29	
30		loopFlags := map[string]bool{}
31		loopCmd.Flags().VisitAll(func(f *pflag.Flag) {
32			loopFlags[f.Name] = true
