2094	// resolveServerURL determines the base URL for the running DDx server.
2095	//
2096	// Resolution order (matches internal/serverreg):
2097	//  1. DDX_SERVER_URL environment variable (explicit override)
2098	//  2. ~/.local/share/ddx/server.addr (written by `ddx server` on startup)
2099	//  3. https://127.0.0.1:7743 (the canonical default — see FEAT-020)
2100	//
2101	// The addr file may record a bind-address URL like https://0.0.0.0:7743
2102	// (because the server binds to 0.0.0.0 for multi-interface access). Those
2103	// are valid listen addresses but not reachable as client targets on some
2104	// platforms — rewrite them to https://127.0.0.1:<port> for local clients.
2105	//
2106	// The probe-common-ports heuristic that used to live here only worked for
2107	// the legacy plaintext http://127.0.0.1:8080 setup and never honored the
2108	// TLS default that's been in place since alpha13. Clients that skipped
2109	// the addr file would silently get a connection refused and tell the
2110	// user the server wasn't running when it was listening on 7743.
2111	func resolveServerURL(projectRoot string) string {
2112		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
2113			return u
2114		}
2115		if u := serverpkg.ReadServerAddr(); u != "" {
2116			return rewriteBindAddrForClient(u)
2117		}
2118		return "https://127.0.0.1:7743"
2119	}
