2121	// rewriteBindAddrForClient converts a bind-address URL into a client-reachable
2122	// URL. 0.0.0.0 (and [::]) are valid listen addresses but not reachable as
2123	// client destinations on all platforms — substitute 127.0.0.1 so local HTTP
2124	// clients can always connect.
2125	func rewriteBindAddrForClient(u string) string {
2126		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
2127			if idx := strings.Index(u, bind); idx >= 0 {
2128				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
2129			}
2130		}
2131		return u
2132	}
