	ctx := context.Background()
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return rows
	}
	byName := make(map[string]agentlib.HarnessInfo, len(infos))
	for _, info := range infos {
		byName[info.Name] = info
	}
	now := time.Now()
	for i := range rows {
		info, ok := byName[rows[i].Harness]
		if !ok {
			continue
		}
		signal := harnessInfoToRoutingSignal(info, now)
		applyUsageCostBasis(&rows[i], info.IsSubscription)
		rows[i].QuotaState = signal.CurrentQuota.State
		if signal.Provider == "" && signal.Source.Kind == "" {
			continue
		}
		rows[i].SignalProvider = signal.Provider
		rows[i].SignalKind = signal.Source.Kind
		rows[i].SignalFreshness = signal.Source.Freshness
		rows[i].SignalBasis = signal.Source.Basis
		rows[i].NativeInputTokens = signal.HistoricalUsage.InputTokens
		rows[i].NativeOutputTokens = signal.HistoricalUsage.OutputTokens
		rows[i].NativeTotalTokens = signal.HistoricalUsage.TotalTokens
		rows[i].NativeSessionCount = signal.HistoricalUsage.SessionCount
		rows[i].NativeQuotaUsedPercent = signal.CurrentQuota.UsedPercent
	}
	return rows
}

func readUsageSessionIndexRecords(logDir, harnessFilter string, since time.Time) ([]usageSessionRecord, error) {
	entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{StartedAfter: &since})
	if err != nil {
		return nil, err
	}
	records := make([]usageSessionRecord, 0, len(entries))
	for _, idx := range entries {
		entry := agent.SessionIndexEntryToLegacy(idx)
		if harnessFilter != "" && entry.Harness != harnessFilter {
			continue
		}
		records = append(records, usageSessionRecord{
			entry: entry,
		})
	}
	sort.Slice(records, func(i, j int) bool {
		return records[i].entry.Timestamp.Before(records[j].entry.Timestamp)
	})
	return records, nil
}

// formatComma formats an integer with comma separators.
func formatComma(n int) string {
	s := strconv.Itoa(n)
	if len(s) <= 3 {
		return s
	}
	var b strings.Builder
	start := len(s) % 3
	b.WriteString(s[:start])
	for i := start; i < len(s); i += 3 {
		if i > 0 {
			b.WriteByte(',')
		}
		b.WriteString(s[i : i+3])
	}
	return b.String()
}

// harnessInfoToRoutingSignal translates an upstream HarnessInfo into the
// RoutingSignalSnapshot shape. Quota status values map to the existing freshness
// vocabulary so CLI output maintains its previous field layout.
func harnessInfoToRoutingSignal(info agentlib.HarnessInfo, now time.Time) agent.RoutingSignalSnapshot {
	if info.Quota == nil && len(info.UsageWindows) == 0 && info.Account == nil {
		return agent.RoutingSignalSnapshot{}
	}

	snap := agent.RoutingSignalSnapshot{Provider: info.Name}
	if info.Account != nil && (info.Account.Email != "" || info.Account.PlanType != "" || info.Account.OrgName != "") {
		snap.Account = &agent.AccountInfo{
			Email:    info.Account.Email,
			PlanType: info.Account.PlanType,
			OrgName:  info.Account.OrgName,
		}
	}

	if info.Quota != nil {
		freshness := "fresh"
		if !info.Quota.Fresh {
			freshness = "stale"
		}
		if info.Quota.Status == "unavailable" || info.Quota.Status == "unauthenticated" {
			freshness = "unknown"
		}
		kind := agent.NormalizeSignalSourceKind(info.Quota.Source)
		var ageSeconds int64
		if !info.Quota.CapturedAt.IsZero() {
			if age := now.UTC().Sub(info.Quota.CapturedAt.UTC()); age > 0 {
				ageSeconds = int64(age.Seconds())
			}
		}
		meta := agent.SignalSourceMetadata{
			Provider:   info.Name,
			Kind:       kind,
			ObservedAt: info.Quota.CapturedAt.UTC(),
			Freshness:  freshness,
			AgeSeconds: ageSeconds,
		}
		state := "unknown"
		switch info.Quota.Status {
		case "ok":
			state = "ok"
		case "stale":
			state = "ok"
		}
		var usedPercent, windowMinutes int
		var resetsAt string
		for _, w := range info.Quota.Windows {
			snap.QuotaWindows = append(snap.QuotaWindows, agent.QuotaWindow{
				Name:          w.Name,
				LimitID:       w.LimitID,
				WindowMinutes: w.WindowMinutes,
				UsedPercent:   w.UsedPercent,
				ResetsAt:      w.ResetsAt,
				ResetsAtUnix:  w.ResetsAtUnix,
				State:         w.State,
			})
			if w.LimitID == "extra" {
				continue
			}
			if w.State == "blocked" {
				state = "blocked"
				resetsAt = w.ResetsAt
			}
			if int(w.UsedPercent+0.5) > usedPercent {
				usedPercent = int(w.UsedPercent + 0.5)
				windowMinutes = w.WindowMinutes
			}
		}
		snap.Source = meta
		snap.CurrentQuota = agent.QuotaSignal{
			Source:        meta,
			State:         state,
			UsedPercent:   usedPercent,
			WindowMinutes: windowMinutes,
			ResetsAt:      resetsAt,
		}
		snap.HistoricalUsage.Source = meta
	}

	for _, u := range info.UsageWindows {
		snap.HistoricalUsage.InputTokens += u.InputTokens
		snap.HistoricalUsage.OutputTokens += u.OutputTokens
		snap.HistoricalUsage.TotalTokens += u.TotalTokens
	}

	return snap
}

