232	func copyTree(src, dst string) error {
233		return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
234			if err != nil {
235				return err
236			}
237			rel, err := filepath.Rel(src, path)
238			if err != nil {
239				return err
240			}
241			target := filepath.Join(dst, rel)
242			if info.IsDir() {
243				return os.MkdirAll(target, info.Mode())
244			}
245			if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
246				return err
247			}
248			in, err := os.Open(path)
249			if err != nil {
250				return err
251			}
252			defer in.Close()
253			out, err := os.Create(target)
254			if err != nil {
255				return err
256			}
257			if _, err := io.Copy(out, in); err != nil {
258				out.Close()
259				return err
260			}
261			if err := out.Close(); err != nil {
262				return err
263			}
264			return os.Chmod(target, info.Mode())
265		})
266	}
